**   date_trunc('day', '2023-10-27 15:00:00') -> '2023-10-27 00:00:00'
*/
static void date_truncFunc(
  sqlite3_context *context,
  int argc,
  sqlite3_value **argv
){
  DateTime x;
  const char *zUnit;
  int unitLen;
  char zBuf[32];
  int Y, s;

  /* Must have exactly 2 arguments */
  if( argc!=2 ){
    sqlite3_result_error(context, "date_trunc() must have exactly 2 arguments", -1);
    return;
  }

  /* Get and validate the unit argument */
  zUnit = (const char*)sqlite3_value_text(argv[0]);
