    return;
  }
  unitLen = sqlite3Strlen30(zUnit);

  /* Normalize to lowercase for comparison */
  /* We'll check the unit directly without modifying the original string */

  /* Parse the timestamp */
  if( isDate(context, 1, &argv[1], &x) ){
    return;  /* Error already set by isDate() */
  }

  /* Ensure YMD and HMS are computed */
  computeYMD_HMS(&x);
  if( x.isError ){
    sqlite3_result_error(context, "date_trunc(): date out of range", -1);
    return;
  }

  /* Truncate based on unit */
  if( sqlite3_strnicmp(zUnit, "year", unitLen)==0 ){
    x.M = 1;
    x.D = 1;
    x.h = 0;
    x.m = 0;
    x.s = 0.0;
  }else if( sqlite3_strnicmp(zUnit, "month", unitLen)==0 ){
    x.D = 1;
    x.h = 0;
    x.m = 0;
    x.s = 0.0;
  }else if( sqlite3_strnicmp(zUnit, "day", unitLen)==0 ){
    x.h = 0;
    x.m = 0;
    x.s = 0.0;
  }else if( sqlite3_strnicmp(zUnit, "hour", unitLen)==0 ){
    x.m = 0;
    x.s = 0.0;
